        okStreak = 0;
        console.warn('[market] ' + res.status + ' — cooldown ' + Math.round(backoff / 1000) + 's (delay→' + BASE_DELAY + 'ms)');
        await sleep(backoff);
        continue;
      }
      // succès : on redescend doucement vers le débit soutenable (decrease additif)
      if (++okStreak % 15 === 0 && BASE_DELAY > MIN_DELAY) {
